// practice 1
// Promiseオブジェクトを返す関数を作る
const delayMessage = (num) => {
  return new Promise((resolve, reject) => {
    // resolveかrejectで処理を分ける
    const result = num >= 0;

    setTimeout(() => {
      if (result) {
        // resolveが呼ばれたら
        resolve(`${num}ミリ秒待機しました`);
      } else {
        // rejectが呼ばれたら
        reject(new Error("負の時間は待機できません"));
      }
    }, num);
  });
};

delayMessage(1000)
  .then((successMessage) => {
    console.log(successMessage);
  })
  .catch((errorMessage) => {
    console.log(errorMessage.message);
  });

// practice 2

// 練習用APIのURLを定義
const apiUrl = "https://jsonplaceholder.typicode.com/todos/5";

// ToDoデータを取得する関数の定義
const fetchTodo = async () => {
  // 1. fetch()でデータを取得
  // 4. try...catchを導入
  try {
    const response = await fetch(apiUrl);

    if (!response.ok) {
      throw new Error("サーバーエラーが発生しました");
    }

    // 2. JSON -< JSが扱えるオブジェクトに変換
    const todoContent = await response.json();

    // 3. titleプロパティを取り出して表示
    const todoTitle = todoContent.title;
    console.log("取得したToDoタイトル: ", todoTitle);
  } catch (error) {
    console.error("データの取得に失敗しました: ", error);
  }
};

fetchTodo();

Response.content:
方向性は合っていますが、少し補足が必要です。

まず前提として、async関数内でエラーが起きても、HTMLの表示自体が止まることは基本的にありません。JavaScriptの実行とHTMLのレンダリングは別の話です。HTMLはJSの実行前にパースされて表示されます。

ただし、エラーが起きると困ることはあります：

- エラー以降のJS処理が実行されない（例：取得したデータの表示処理がスキップされる）
- コンソールに未処理エラー（`Unhandled Promise Rejection`）が出る
- ユーザーに何が起きたか伝わらない

`try...catch` の目的は「エラーを握りつぶす」ことではなく、エラーが起きたときに適切に対応することです。

```js
// try...catchなし → エラー時に何も制御できない
const fetchTodo = async () => {
  const response = await fetch(apiUrl);  // ネットワーク切断 → 未処理エラー
  const data = await response.json();
  console.log(data.title);               // ここは実行されない
};

// try...catchあり → エラー時にフォールバック処理ができる
const fetchTodo = async () => {
  try {
    const response = await fetch(apiUrl);
    if (!response.ok) throw new Error("サーバーエラー");
    const data = await response.json();
    console.log(data.title);
  } catch (error) {
    // ユーザーに「読み込み失敗」と表示する、リトライする、等
    console.error("取得失敗:", error);
  }
};
```

なので整理すると：

- async関数のエラーでHTMLの表示が消えるわけではない
- `try...catch` は「エラーをなかったことにする」のではなく「エラー時にどうするかを自分で決める」ための仕組み
- これがないと、エラー後の処理が全部スキップされ、ユーザーには何も起きていないように見えてしまう（データが表示されないまま放置される等）

その通りです。async関数の中で発生した例外が `try...catch` 等で捕捉されずに外まで漏れたとき、その関数が返すPromiseがrejectedになります。

```js
// rejectedになる → エラーが捕捉されていない
const fetchTodo = async () => {
  const response = await fetch(apiUrl); // ここで失敗したら即rejected
  const data = await response.json();
  console.log(data.title);
};

// rejectedにならない → catchが捕捉している
const fetchTodo = async () => {
  try {
    const response = await fetch(apiUrl); // ここで失敗しても…
    const data = await response.json();
    console.log(data.title);
  } catch (error) {
    console.error("失敗:", error);        // …catchが処理するのでfulfilled
  }
};
```

なので「rejectedになる＝未処理の例外が関数の外に飛び出す」と覚えておけばOKです。

はい、基本的にはそうです。async関数内では `try...catch` でエラーを捕捉するのがベストプラクティスです。

未処理のrejectedが残ると、ブラウザのコンソールに `Unhandled Promise Rejection` の警告が出ますし、Node.jsではプロセスがクラッシュする可能性もあります。

ただし、どこで捕捉するかは設計次第です：

```js
// パターン1: 関数の中で捕捉（今のコード）
const fetchTodo = async () => {
  try {
    const response = await fetch(apiUrl);
    const data = await response.json();
    console.log(data.title);
  } catch (error) {
    console.error("失敗:", error);
  }
};

fetchTodo();

// パターン2: 呼び出し側で捕捉
const fetchTodo = async () => {
  const response = await fetch(apiUrl);
  const data = await response.json();
  return data.title;
};

fetchTodo()
  .then((title) => console.log(title))
  .catch((error) => console.error("失敗:", error));
```

どちらでもいいですが、「どこかで必ず捕捉する」ことが大事です。どこにも `catch` がないのが一番まずいパターンです。

